var s = msg.payload;
if (!s || typeof s.serialNumber !== 'string' || !s.timestamp) {
    node.error('Invalid VDA5050 state message', msg);
    return null;
}
var pos = s.agvPosition || {};
node.status({ fill: 'green', shape: 'dot', text: s.serialNumber + ' x:' + (pos.x || 0).toFixed(2) + ' y:' + (pos.y || 0).toFixed(2) });
msg.headers = { 'content-type': 'application/json' };
msg.payload = s;
msg.url = 'http://' + (env.get('FASTAPI_HOST') || 'localhost') + ':8000/ingest/state';
return msg;

var c = msg.payload;
var VALID = ['ONLINE', 'OFFLINE', 'CONNECTIONBROKEN'];
if (!c || typeof c.serialNumber !== 'string' || VALID.indexOf(c.connectionState) === -1) {
    node.error('Invalid VDA5050 connection message', msg);
    return null;
}
var fill = c.connectionState === 'ONLINE' ? 'green' : c.connectionState === 'OFFLINE' ? 'grey' : 'red';
node.status({ fill: fill, shape: 'dot', text: c.serialNumber + ': ' + c.connectionState });
msg.headers = { 'content-type': 'application/json' };
msg.payload = c;
msg.url = 'http://' + (env.get('FASTAPI_HOST') || 'localhost') + ':8000/ingest/connection';
return msg;

var m = msg.payload;
if (!m || typeof m.serialNumber !== 'string' || typeof m.orderId !== 'string') {
    node.error('Invalid order message', msg);
    return null;
}
node.status({ fill: 'blue', shape: 'dot', text: m.serialNumber + ' ' + m.orderId });
msg.headers = { 'content-type': 'application/json' };
msg.payload = { kind: 'order', message: m };
msg.url = 'http://' + (env.get('FASTAPI_HOST') || 'localhost') + ':8000/ingest/command';
return msg;

var m = msg.payload;
if (!m || typeof m.serialNumber !== 'string' || !Array.isArray(m.actions)) {
    node.error('Invalid instantActions message', msg);
    return null;
}
var types = m.actions.map(function (a) { return a.actionType; }).join(',');
node.status({ fill: 'blue', shape: 'dot', text: m.serialNumber + ' ' + types });
msg.headers = { 'content-type': 'application/json' };
msg.payload = { kind: 'instantActions', message: m };
msg.url = 'http://' + (env.get('FASTAPI_HOST') || 'localhost') + ':8000/ingest/command';
return msg;

var s = msg.payload;
if (!s || typeof s.serialNumber !== 'string') { return null; }
var serial = s.serialNumber;
var key = 'oee_' + serial;
var ctx = flow.get(key) || { orderId: '', startTime: null, active: false };
var cur = s.orderId || '';
var remaining = (s.nodeStates || []).length;
var cycle = null;

if (cur && cur !== ctx.orderId) {
    // a new order has started
    ctx = { orderId: cur, startTime: s.timestamp, active: true };
} else if (cur && cur === ctx.orderId && ctx.active && remaining === 0) {
    // the active order has finished all of its nodes
    cycle = { serialNumber: serial, orderId: cur, startTime: ctx.startTime, endTime: s.timestamp, result: 'SUCCEEDED' };
    ctx.active = false;
} else if (!cur && ctx.active) {
    // the order was cleared (cancelled) while still active
    cycle = { serialNumber: serial, orderId: ctx.orderId, startTime: ctx.startTime, endTime: s.timestamp, result: 'ABORTED' };
    ctx = { orderId: '', startTime: null, active: false };
}

flow.set(key, ctx);
if (!cycle) { return null; }

var dur = (new Date(cycle.endTime) - new Date(cycle.startTime)) / 1000;
cycle.durationS = Math.max(0, Math.round(dur * 10) / 10);
node.status({ fill: cycle.result === 'SUCCEEDED' ? 'green' : 'red', shape: 'dot', text: cycle.orderId + ' ' + cycle.result + ' (' + cycle.durationS + 's)' });
msg.headers = { 'content-type': 'application/json' };
msg.payload = cycle;
msg.url = 'http://' + (env.get('FASTAPI_HOST') || 'localhost') + ':8000/ingest/oee-cycle';
return msg;
